package util

import (
	"fmt"
	"os"

	"gorm.io/driver/postgres"
	"gorm.io/gorm"
)

var DB *gorm.DB

// DBConfig holds the normalized database configuration.
type DBConfig struct {
	Host     string
	Port     string
	User     string
	Password string
	Name     string
	SSLMode  string
	TimeZone string
}

// DBFactory provides a hook to open a database using a given configuration.
type DBFactory interface {
	Open(DBConfig) (*gorm.DB, error)
}

// PostgresFactory implements DBFactory using the postgres driver.
type PostgresFactory struct {
	GormConfig *gorm.Config
}

// LoadDBConfigFromEnv normalizes env vars into a DBConfig.
func LoadDBConfigFromEnv() (DBConfig, error) {
	cfg := DBConfig{
		Host:     firstNonEmpty(os.Getenv("DB_HOST"), os.Getenv("DBHOST")),
		User:     firstNonEmpty(os.Getenv("POSTGRES_USER"), os.Getenv("DB_USER")),
		Password: firstNonEmpty(os.Getenv("POSTGRES_PASSWORD"), os.Getenv("DB_PASS"), os.Getenv("DB_PASSWORD")),
		Name:     firstNonEmpty(os.Getenv("POSTGRES_DATABASE"), os.Getenv("POSTGRES_DB"), os.Getenv("DB_NAME")),
		Port:     firstNonEmpty(os.Getenv("POSTGRES_PORT"), os.Getenv("DB_PORT"), "5432"),
		SSLMode:  "disable",
		TimeZone: "UTC",
	}

	if cfg.Host == "" {
		return DBConfig{}, fmt.Errorf("missing DB host (DB_HOST or DBHOST)")
	}
	if cfg.User == "" {
		return DBConfig{}, fmt.Errorf("missing DB user (POSTGRES_USER or DB_USER)")
	}
	if cfg.Name == "" {
		return DBConfig{}, fmt.Errorf("missing DB name (POSTGRES_DATABASE/POSTGRES_DB/DB_NAME)")
	}

	return cfg, nil
}

// BuildPostgresDSN assembles the postgres DSN from config.
func BuildPostgresDSN(cfg DBConfig) (string, error) {
	if cfg.Host == "" || cfg.User == "" || cfg.Name == "" {
		return "", fmt.Errorf("invalid DB config: host/user/name required")
	}

	port := cfg.Port
	if port == "" {
		port = "5432"
	}

	sslMode := cfg.SSLMode
	if sslMode == "" {
		sslMode = "disable"
	}

	timeZone := cfg.TimeZone
	if timeZone == "" {
		timeZone = "UTC"
	}

	dsn := fmt.Sprintf(
		"host=%s user=%s password=%s dbname=%s port=%s sslmode=%s TimeZone=%s",
		cfg.Host,
		cfg.User,
		cfg.Password,
		cfg.Name,
		port,
		sslMode,
		timeZone,
	)

	return dsn, nil
}

// Open opens a postgres-backed gorm DB using the provided configuration.
func (f PostgresFactory) Open(cfg DBConfig) (*gorm.DB, error) {
	dsn, err := BuildPostgresDSN(cfg)
	if err != nil {
		return nil, err
	}

	gormCfg := f.GormConfig
	if gormCfg == nil {
		gormCfg = &gorm.Config{}
	}

	return gorm.Open(postgres.Open(dsn), gormCfg)
}

// InitDB initializes the global DB with the provided factory and config.
func InitDB(cfg DBConfig, factory DBFactory) (*gorm.DB, error) {
	if factory == nil {
		factory = PostgresFactory{}
	}

	db, err := factory.Open(cfg)
	if err != nil {
		return nil, fmt.Errorf("open db: %w", err)
	}

	DB = db
	return db, nil
}

// GetDB returns the database connection.
func GetDB() *gorm.DB {
	return DB
}

func firstNonEmpty(values ...string) string {
	for _, v := range values {
		if v != "" {
			return v
		}
	}
	return ""
}

package security

import (
	"fmt"
	"net/url"
	"regexp"
	"strings"
	"unicode"

	"github.com/microcosm-cc/bluemonday"
)

// Sanitizer holds the bluemonday policies for different content types
type Sanitizer struct {
	strictPolicy *bluemonday.Policy
	basicPolicy  *bluemonday.Policy
}

// NewSanitizer creates a new sanitizer with predefined policies
func NewSanitizer() *Sanitizer {
	return &Sanitizer{
		strictPolicy: bluemonday.StrictPolicy(),
		basicPolicy:  createBasicPolicy(),
	}
}

// createBasicPolicy creates a policy that allows basic text formatting but removes scripts
func createBasicPolicy() *bluemonday.Policy {
	p := bluemonday.NewPolicy()
	// Allow basic text formatting
	p.AllowElements("b", "i", "em", "strong")
	// Ensure no scripts, iframes, or dangerous elements
	p.AllowAttrs("href").OnElements("a")
	p.RequireNoReferrerOnLinks(true)
	return p
}

// SanitizeUsername removes any characters that are not lowercase letters or numbers
func (s *Sanitizer) SanitizeUsername(username string) (string, error) {
	// Remove any whitespace
	username = strings.TrimSpace(username)

	// Check if username matches expected pattern
	if match, _ := regexp.MatchString("^[a-z0-9]+$", username); !match {
		return "", fmt.Errorf("username must only contain lowercase letters and numbers")
	}

	// Additional length check
	if len(username) < 3 || len(username) > 30 {
		return "", fmt.Errorf("username must be between 3 and 30 characters")
	}

	return username, nil
}

// SanitizeDisplayName removes HTML/script content but allows basic formatting
func (s *Sanitizer) SanitizeDisplayName(displayName string) (string, error) {
	// Remove leading/trailing whitespace
	displayName = strings.TrimSpace(displayName)

	// Check length
	if len(displayName) == 0 {
		return "", fmt.Errorf("display name cannot be empty")
	}
	if len(displayName) > 50 {
		return "", fmt.Errorf("display name cannot exceed 50 characters")
	}

	// Check for potentially dangerous patterns before sanitizing
	if containsSuspiciousPatterns(displayName) {
		return "", fmt.Errorf("display name contains potentially dangerous content")
	}

	// Sanitize HTML/script content
	sanitized := s.strictPolicy.Sanitize(displayName)

	return sanitized, nil
}

// SanitizeDescription removes dangerous HTML while allowing basic formatting
func (s *Sanitizer) SanitizeDescription(description string) (string, error) {
	// Remove leading/trailing whitespace
	description = strings.TrimSpace(description)

	// Check length
	if len(description) > 2000 {
		return "", fmt.Errorf("description cannot exceed 2000 characters")
	}

	// Check for suspicious patterns before sanitizing
	if containsSuspiciousPatterns(description) {
		return "", fmt.Errorf("description contains potentially dangerous content")
	}

	// Sanitize with basic policy (allows some formatting)
	sanitized := s.basicPolicy.Sanitize(description)

	return sanitized, nil
}

// SanitizeMarketTitle sanitizes market question titles
func (s *Sanitizer) SanitizeMarketTitle(title string) (string, error) {
	// Remove leading/trailing whitespace
	title = strings.TrimSpace(title)

	// Check length constraints
	if len(title) == 0 {
		return "", fmt.Errorf("market title cannot be empty")
	}
	if len(title) > 160 {
		return "", fmt.Errorf("market title cannot exceed 160 characters")
	}

	// Check for suspicious patterns before sanitizing
	if containsSuspiciousPatterns(title) {
		return "", fmt.Errorf("market title contains potentially dangerous content")
	}

	// Sanitize HTML/script content
	sanitized := s.strictPolicy.Sanitize(title)

	return sanitized, nil
}

// SanitizePersonalLink validates and sanitizes personal links
func (s *Sanitizer) SanitizePersonalLink(link string) (string, error) {
	link = strings.TrimSpace(link)
	if link == "" {
		return "", nil
	}

	if err := validatePersonalLinkLength(link); err != nil {
		return "", err
	}

	parsedURL, err := parseURLWithScheme(link)
	if err != nil {
		return "", err
	}

	if err := validateAllowedScheme(parsedURL.Scheme); err != nil {
		return "", err
	}

	if containsMaliciousDomain(parsedURL.Host) {
		return "", fmt.Errorf("potentially malicious domain detected")
	}

	return parsedURL.String(), nil
}

func validatePersonalLinkLength(link string) error {
	if len(link) > 200 {
		return fmt.Errorf("personal link cannot exceed 200 characters")
	}
	return nil
}

func parseURLWithScheme(link string) (*url.URL, error) {
	parsedURL, err := url.Parse(link)
	if err != nil {
		return nil, fmt.Errorf("invalid URL format: %v", err)
	}

	if parsedURL.Scheme != "" {
		return parsedURL, nil
	}

	withScheme := "https://" + link
	parsedURL, err = url.Parse(withScheme)
	if err != nil {
		return nil, fmt.Errorf("invalid URL format after adding scheme: %v", err)
	}
	return parsedURL, nil
}

func validateAllowedScheme(scheme string) error {
	if scheme != "http" && scheme != "https" {
		return fmt.Errorf("only http and https URLs are allowed")
	}
	return nil
}

// SanitizeEmoji validates that the emoji is from an allowed set
func (s *Sanitizer) SanitizeEmoji(emoji string) (string, error) {
	// Remove leading/trailing whitespace
	emoji = strings.TrimSpace(emoji)

	// Check if it's a valid emoji (basic check for unicode emoji ranges)
	if !isValidEmoji(emoji) {
		return "", fmt.Errorf("invalid emoji format")
	}

	// Check length (emojis should be short)
	if len(emoji) > 20 {
		return "", fmt.Errorf("emoji too long")
	}

	return emoji, nil
}

// SanitizePassword validates password strength
func (s *Sanitizer) SanitizePassword(password string) (string, error) {

	// Basic length checks
	password, err := s.CheckPasswordLength(password)
	if err != nil {
		return "", err
	}

	password, err = s.CheckPasswordChars(password)
	if err != nil {
		return "", err
	}

	return password, nil
}

func (s *Sanitizer) CheckPasswordLength(password string) (string, error) {
	const minLength = 8
	const maxLength = 128

	// Check length constraints
	len := len(password)
	if len < minLength || len > maxLength {
		return "", fmt.Errorf("password must be between %d and %d characters long", minLength, maxLength)
	}

	return password, nil
}

// CheckChars checks for the presence of uppercase, lowercase, and digit characters
func (s *Sanitizer) CheckPasswordChars(password string) (string, error) {
	if !(hasUppercase(password) && hasLowercase(password) && hasDigit(password)) {
		return "", fmt.Errorf("password must contain at least one uppercase letter, one lowercase letter, and one digit")
	}

	return password, nil
}

// containsSuspiciousPatterns checks for common XSS and injection patterns
func containsSuspiciousPatterns(input string) bool {
	suspiciousPatterns := []string{
		"javascript:",
		"vbscript:",
		"data:",
		"<script",
		"</script>",
		"<iframe",
		"<object",
		"<embed",
		"<link",
		"<meta",
		"<style",
		"onload=",
		"onerror=",
		"onclick=",
		"onmouseover=",
		"onfocus=",
		"onblur=",
		"onchange=",
		"onsubmit=",
		"eval(",
		"expression(",
		"url(",
		"@import",
		"<!--",
		"-->",
	}

	inputLower := strings.ToLower(input)
	for _, pattern := range suspiciousPatterns {
		if strings.Contains(inputLower, pattern) {
			return true
		}
	}

	return false
}

// containsMaliciousDomain checks against known malicious domain patterns
func containsMaliciousDomain(domain string) bool {
	// This is a basic implementation - in production, you'd use a more comprehensive list
	maliciousPatterns := []string{
		"bit.ly", // URL shorteners can be used maliciously
		"tinyurl.com",
		"t.co",
		"localhost", // Prevent internal network access
		"127.0.0.1",
		"0.0.0.0",
		"::1",
		"169.254.", // Link-local addresses
		"10.",      // Private network ranges
		"192.168.",
		"172.16.",
	}

	domainLower := strings.ToLower(domain)
	for _, pattern := range maliciousPatterns {
		if strings.Contains(domainLower, pattern) {
			return true
		}
	}

	return false
}

// isValidEmoji performs basic emoji validation
func isValidEmoji(emoji string) bool {
	if emoji == "" {
		return false
	}

	for _, r := range emoji {
		if isEmojiRune(r) || isASCIIEmojiRune(r) {
			continue
		}
		return false
	}
	return true
}

type runeRange struct {
	start rune
	end   rune
}

// Common emoji ranges (simplified)
var emojiRanges = []runeRange{
	{start: 0x1F600, end: 0x1F64F}, // Emoticons
	{start: 0x1F300, end: 0x1F5FF}, // Misc Symbols
	{start: 0x1F680, end: 0x1F6FF}, // Transport
	{start: 0x2600, end: 0x26FF},   // Misc symbols
	{start: 0x2700, end: 0x27BF},   // Dingbats
	{start: 0xFE00, end: 0xFE0F},   // Variation selectors
	{start: 0x1F900, end: 0x1F9FF}, // Supplemental symbols
	{start: 0x1F1E6, end: 0x1F1FF}, // Regional indicators
}

func isEmojiRune(r rune) bool {
	for _, emojiRange := range emojiRanges {
		if r >= emojiRange.start && r <= emojiRange.end {
			return true
		}
	}
	return false
}

func isASCIIEmojiRune(r rune) bool {
	// Allow basic ASCII characters for simple emojis like :)
	return r >= 32 && r <= 126
}

func hasUppercase(s string) bool {
	for _, char := range s {
		if unicode.IsUpper(char) {
			return true
		}
	}
	return false

package auth

import (
	"encoding/json"
	"errors"
	"fmt"
	"net/http"
	"os"
	"socialpredict/models"
	"socialpredict/security"
	"socialpredict/util"
	"time"

	"github.com/golang-jwt/jwt/v4"
	"gorm.io/gorm"
)

// login and validation stuff
// getJWTKey returns the JWT signing key, checking environment variable at runtime
func getJWTKey() []byte {
	return []byte(os.Getenv("JWT_SIGNING_KEY"))
}

// UserClaims represents the expected structure of the JWT claims
type UserClaims struct {
	Username string `json:"username"`
	jwt.StandardClaims
}

func LoginHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method is not supported.", http.StatusNotFound)
		return
	}

	securityService := security.NewSecurityService()

	req, err := decodeLoginRequest(r)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	req, err = validateAndSanitizeLogin(securityService, req)
	if err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	user, loginErr := authenticateUser(req)
	if loginErr != nil {
		http.Error(w, loginErr.message, loginErr.statusCode)
		return
	}

	tokenString, err := generateJWT(user.Username)
	if err != nil {
		http.Error(w, "Error creating token", http.StatusInternalServerError)
		return
	}

	writeLoginResponse(w, user, tokenString)
}

type loginRequest struct {
	Username string `json:"username" validate:"required,min=3,max=30,username"`
	Password string `json:"password" validate:"required,min=1"`
}

func decodeLoginRequest(r *http.Request) (loginRequest, error) {
	var req loginRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		return loginRequest{}, fmt.Errorf("Error reading request body")
	}
	return req, nil
}

func validateAndSanitizeLogin(securityService *security.SecurityService, req loginRequest) (loginRequest, error) {
	if err := securityService.Validator.ValidateStruct(req); err != nil {
		return req, fmt.Errorf("Invalid input: %w", err)
	}

	sanitizedUsername, err := securityService.Sanitizer.SanitizeUsername(req.Username)
	if err != nil {
		return req, fmt.Errorf("Invalid username format")
	}
	req.Username = sanitizedUsername
	return req, nil
}

type loginError struct {
	message    string
	statusCode int
}

func authenticateUser(req loginRequest) (models.User, *loginError) {
	user, err := findUserByUsername(req.Username)
	if err != nil {
		if errors.Is(err, gorm.ErrRecordNotFound) {
			return models.User{}, &loginError{message: "Invalid Credentials", statusCode: http.StatusUnauthorized}
		}
		return models.User{}, &loginError{message: "Error accessing database", statusCode: http.StatusInternalServerError}
	}

	if !user.CheckPasswordHash(req.Password) {
		return models.User{}, &loginError{message: "Invalid Credentials", statusCode: http.StatusUnauthorized}
	}

	return user, nil
}

func findUserByUsername(username string) (models.User, error) {
	db := util.GetDB()
	var user models.User
	result := db.Where("username = ?", username).First(&user)
	return user, result.Error
}

func generateJWT(username string) (string, error) {
	claims := &UserClaims{
		Username: username,
		StandardClaims: jwt.StandardClaims{
			ExpiresAt: time.Now().Add(24 * time.Hour).Unix(),
		},
	}

	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
	return token.SignedString(getJWTKey())
}

func writeLoginResponse(w http.ResponseWriter, user models.User, tokenString string) {
	w.Header().Set("Content-Type", "application/json")

	responseData := map[string]interface{}{
		"token":              tokenString,
		"username":           user.Username,
		"usertype":           user.UserType,
		"mustChangePassword": user.MustChangePassword,
	}
	_ = json.NewEncoder(w).Encode(responseData)
}

}

func hasLowercase(s string) bool {
	for _, char := range s {
		if unicode.IsLower(char) {
			return true
		}
	}
	return false
}

func hasDigit(s string) bool {
	for _, char := range s {
		if unicode.IsDigit(char) {
			return true
		}
	}
	return false
}

package auth

import (
	"bytes"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"os"
	"socialpredict/models/modelstesting"
	"testing"
	"time"

	dusers "socialpredict/internal/domain/users"
	rusers "socialpredict/internal/repository/users"
	"socialpredict/security"

	"github.com/golang-jwt/jwt/v4"
)

func TestHTTPError(t *testing.T) {
	err := &HTTPError{
		StatusCode: 404,
		Message:    "Not found",
	}

	if err.Error() != "Not found" {
		t.Errorf("Expected 'Not found', got '%s'", err.Error())
	}

	if err.StatusCode != 404 {
		t.Errorf("Expected status code 404, got %d", err.StatusCode)
	}
}

func TestExtractTokenFromHeader(t *testing.T) {
	tests := []struct {
		name          string
		header        string
		expectedToken string
		expectError   bool
	}{
		{
			name:          "Valid Bearer token",
			header:        "Bearer abc123token",
			expectedToken: "abc123token",
			expectError:   false,
		},
		{
			name:        "Missing Authorization header",
			header:      "",
			expectError: true,
		},
		{
			name:          "Token without Bearer prefix",
			header:        "abc123token",
			expectedToken: "abc123token",
			expectError:   false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			req := httptest.NewRequest("GET", "/test", nil)
			if tt.header != "" {
				req.Header.Set("Authorization", tt.header)
			}

			token, err := extractTokenFromHeader(req)

			if tt.expectError {
				if err == nil {
					t.Errorf("Expected error but got none")
				}
			} else {
				if err != nil {
					t.Errorf("Expected no error but got: %v", err)
				}
				if token != tt.expectedToken {
					t.Errorf("Expected token '%s', got '%s'", tt.expectedToken, token)
				}
			}
		})
	}
}

func TestParseToken(t *testing.T) {
	// Set up JWT key for testing via environment variable
	originalKey := os.Getenv("JWT_SIGNING_KEY")
	os.Setenv("JWT_SIGNING_KEY", "test-secret-key")
	defer func() { os.Setenv("JWT_SIGNING_KEY", originalKey) }()

	tests := []struct {
		name        string
		tokenString string
		expectError bool
	}{
		{
			name:        "Invalid token",
			tokenString: "invalid.token.here",
			expectError: true,
		},
		{
			name:        "Empty token",
			tokenString: "",
			expectError: true,
		},
	}

	keyFunc := func(token *jwt.Token) (interface{}, error) {
		return getJWTKey(), nil
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			_, err := parseToken(tt.tokenString, keyFunc)

			if tt.expectError {
				if err == nil {
					t.Errorf("Expected error but got none")
				}
			} else {
				if err != nil {
					t.Errorf("Expected no error but got: %v", err)
				}
			}
		})
	}
}

func TestCheckMustChangePasswordFlag(t *testing.T) {
	tests := []struct {
		name               string
		mustChangePassword bool
		expectError        bool
	}{
		{
			name:               "Password change required",
			mustChangePassword: true,
			expectError:        true,
		},
		{
			name:               "Password change not required",
			mustChangePassword: false,
			expectError:        false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			user := &dusers.User{
				MustChangePassword: tt.mustChangePassword,
			}

			httpErr := CheckMustChangePasswordFlag(user)

			if tt.expectError {
				if httpErr == nil {
					t.Errorf("Expected error but got none")
				} else if httpErr.StatusCode != http.StatusForbidden {
					t.Errorf("Expected status code %d, got %d", http.StatusForbidden, httpErr.StatusCode)
				}
			} else {
				if httpErr != nil {
					t.Errorf("Expected no error but got: %v", httpErr)
				}
			}
		})
	}
}

func TestLoginHandler_MethodValidation(t *testing.T) {
	tests := []struct {
		name           string
		method         string
		expectedStatus int
	}{
		{
			name:           "Valid POST method",
			method:         http.MethodPost,
			expectedStatus: http.StatusBadRequest, // Will fail due to invalid body, but method is accepted
		},
		{
			name:           "Invalid GET method",
			method:         http.MethodGet,
			expectedStatus: http.StatusNotFound,
		},
		{
			name:           "Invalid PUT method",
			method:         http.MethodPut,
			expectedStatus: http.StatusNotFound,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			req := httptest.NewRequest(tt.method, "/login", nil)
			w := httptest.NewRecorder()

			LoginHandler(w, req)

			if w.Code != tt.expectedStatus {
				t.Errorf("Expected status code %d, got %d", tt.expectedStatus, w.Code)
			}
		})
	}
}

func TestLoginHandler_InvalidJSON(t *testing.T) {
	invalidJSON := "{ invalid json }"
	req := httptest.NewRequest(http.MethodPost, "/login", bytes.NewBufferString(invalidJSON))
	w := httptest.NewRecorder()

	LoginHandler(w, req)

	if w.Code != http.StatusBadRequest {
		t.Errorf("Expected status code %d, got %d", http.StatusBadRequest, w.Code)
	}
}

func TestLoginHandler_ValidationFailure(t *testing.T) {
	tests := []struct {
		name     string
		username string
		password string
	}{
		{
			name:     "Empty username",
			username: "",
			password: "password123",
		},
		{
			name:     "Empty password",
			username: "testuser",
			password: "",
		},
		{
			name:     "Invalid username format",
			username: "Test@User",
			password: "password123",
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			loginReq := map[string]string{
				"username": tt.username,
				"password": tt.password,
			}
			jsonData, _ := json.Marshal(loginReq)

