 71		if cfg.Host == "" || cfg.User == "" || cfg.Name == "" {
 72			return "", fmt.Errorf("invalid DB config: host/user/name required")
 73		}
 74	
 75		port := cfg.Port
 76		if port == "" {
 77			port = "5432"
 78		}
 79	
 80		sslMode := cfg.SSLMode
 81		if sslMode == "" {
 82			sslMode = "disable"
 83		}
 84	
 85		timeZone := cfg.TimeZone
 86		if timeZone == "" {
 87			timeZone = "UTC"
 88		}
 89	
 90		dsn := fmt.Sprintf(
 91			"host=%s user=%s password=%s dbname=%s port=%s sslmode=%s TimeZone=%s",
 92			cfg.Host,
 93			cfg.User,
 94			cfg.Password,
 95			cfg.Name,
 96			port,
 97			sslMode,
 98			timeZone,
 99		)
100	
101		return dsn, nil
102	}
