104	// Open opens a postgres-backed gorm DB using the provided configuration.
105	func (f PostgresFactory) Open(cfg DBConfig) (*gorm.DB, error) {
106		dsn, err := BuildPostgresDSN(cfg)
107		if err != nil {
108			return nil, err
109		}
110	
111		gormCfg := f.GormConfig
112		if gormCfg == nil {
113			gormCfg = &gorm.Config{}
114		}
115	
116		return gorm.Open(postgres.Open(dsn), gormCfg)
117	}
118	
119	// InitDB initializes the global DB with the provided factory and config.
120	func InitDB(cfg DBConfig, factory DBFactory) (*gorm.DB, error) {
121		if factory == nil {
122			factory = PostgresFactory{}
123		}
124	
125		db, err := factory.Open(cfg)
126		if err != nil {
127			return nil, fmt.Errorf("open db: %w", err)
128		}
129		if db == nil {
130			return nil, fmt.Errorf("open db: factory returned nil db")
131		}
132	
133		dbMu.Lock()
134		DB = db
135		dbMu.Unlock()
136		return db, nil
137	}
