 19	// login and validation stuff
 20	// getJWTKey returns the JWT signing key, checking environment variable at runtime
 21	func getJWTKey() []byte {
 22		return []byte(os.Getenv("JWT_SIGNING_KEY"))
 23	}
 24	
 25	// UserClaims represents the expected structure of the JWT claims
 26	type UserClaims struct {
 27		Username string `json:"username"`
 28		jwt.StandardClaims
 29	}
 30	
 31	func LoginHandler(w http.ResponseWriter, r *http.Request) {
 32		if r.Method != http.MethodPost {
 33			http.Error(w, "Method is not supported.", http.StatusNotFound)
 34			return
 35		}
 36	
 37		db := util.GetDB()
 38		if db == nil {
 39			http.Error(w, "Error accessing database", http.StatusInternalServerError)
 40			return
 41		}
 42	
 43		jwtKey := getJWTKey()
 44		if len(jwtKey) == 0 {
 45			http.Error(w, "Error creating token", http.StatusInternalServerError)
 46			return
 47		}
 48	
 49		securityService := security.NewSecurityService()
 50	
 51		req, err := decodeLoginRequest(r)
 52		if err != nil {
 53			http.Error(w, err.Error(), http.StatusBadRequest)
 54			return
 55		}
 56	
 57		req, err = validateAndSanitizeLogin(securityService, req)
 58		if err != nil {
 59			http.Error(w, err.Error(), http.StatusBadRequest)
 60			return
 61		}
 62	
 63		user, loginErr := authenticateUser(db, req)
 64		if loginErr != nil {
 65			http.Error(w, loginErr.message, loginErr.statusCode)
 66			return
 67		}
 68	
 69		tokenString, err := generateJWT(user.Username, jwtKey)
 70		if err != nil {
 71			http.Error(w, "Error creating token", http.StatusInternalServerError)
 72			return
 73		}
 74	
 75		writeLoginResponse(w, user, tokenString)
 76	}
 77	
 78	type loginRequest struct {
 79		Username string `json:"username" validate:"required,min=3,max=30,username"`
 80		Password string `json:"password" validate:"required,min=1"`
 81	}
 82	
 83	func decodeLoginRequest(r *http.Request) (loginRequest, error) {
 84		var req loginRequest
 85		decoder := json.NewDecoder(io.LimitReader(r.Body, 1<<20))
 86		decoder.DisallowUnknownFields()
 87		if err := decoder.Decode(&req); err != nil {
 88			return loginRequest{}, fmt.Errorf("error reading request body")
 89		}
 90		if err := decoder.Decode(&struct{}{}); err != io.EOF {
 91			return loginRequest{}, fmt.Errorf("error reading request body")
 92		}
 93		return req, nil
 94	}
 95	
 96	func validateAndSanitizeLogin(securityService *security.SecurityService, req loginRequest) (loginRequest, error) {
 97		sanitizedUsername, err := securityService.Sanitizer.SanitizeUsername(req.Username)
 98		if err != nil {
 99			return req, fmt.Errorf("Invalid username format")
100		}
101		req.Username = sanitizedUsername
102	
103		if err := securityService.Validator.ValidateStruct(req); err != nil {
104			return req, fmt.Errorf("Invalid input: %w", err)
105		}
106	
107		return req, nil
108	}
109	
110	type loginError struct {
111		message    string
112		statusCode int
113	}
114	
115	func authenticateUser(db *gorm.DB, req loginRequest) (models.User, *loginError) {
116		if db == nil {
117			return models.User{}, &loginError{message: "Error accessing database", statusCode: http.StatusInternalServerError}
118		}
119	
120		user, err := findUserByUsername(db, req.Username)
121		if err != nil {
122			if errors.Is(err, gorm.ErrRecordNotFound) {
123				return models.User{}, &loginError{message: "Invalid Credentials", statusCode: http.StatusUnauthorized}
124			}
125			return models.User{}, &loginError{message: "Error accessing database", statusCode: http.StatusInternalServerError}
126		}
127	
128		if !user.CheckPasswordHash(req.Password) {
129			return models.User{}, &loginError{message: "Invalid Credentials", statusCode: http.StatusUnauthorized}
130		}
131	
132		return user, nil
133	}
134	
135	func findUserByUsername(db *gorm.DB, username string) (models.User, error) {
136		var user models.User
137		result := db.Where("username = ?", username).First(&user)
138		return user, result.Error
139	}
140	
141	func generateJWT(username string, jwtKey []byte) (string, error) {
142		if len(jwtKey) == 0 {
143			return "", fmt.Errorf("missing JWT signing key")
144		}
145	
146		claims := &UserClaims{
147			Username: username,
148			StandardClaims: jwt.StandardClaims{
149				ExpiresAt: time.Now().UTC().Add(24 * time.Hour).Unix(),
150			},
151		}
152	
153		token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
154		return token.SignedString(jwtKey)
155	}
156	
157	func writeLoginResponse(w http.ResponseWriter, user models.User, tokenString string) {
158		w.Header().Set("Content-Type", "application/json")
159		w.WriteHeader(http.StatusOK)
160	
161		responseData := map[string]interface{}{
162			"token":              tokenString,
163			"username":           user.Username,
164			"usertype":           user.UserType,
165			"mustChangePassword": user.MustChangePassword,
166		}
167		_ = json.NewEncoder(w).Encode(responseData)
168	}

