 15	var usernamePattern = regexp.MustCompile("^[a-z0-9]+$")
 16	
 17	// Sanitizer holds the bluemonday policies for different content types
 18	type Sanitizer struct {
 19		strictPolicy *bluemonday.Policy
 20		basicPolicy  *bluemonday.Policy
 21	}
 22	
 23	// NewSanitizer creates a new sanitizer with predefined policies
 24	func NewSanitizer() *Sanitizer {
 25		return &Sanitizer{
 26			strictPolicy: bluemonday.StrictPolicy(),
 27			basicPolicy:  createBasicPolicy(),
 28		}
 29	}
 30	
 31	// createBasicPolicy creates a policy that allows basic text formatting but removes scripts
 32	func createBasicPolicy() *bluemonday.Policy {
 33		p := bluemonday.NewPolicy()
 34		p.AllowStandardURLs()
 35		p.RequireParseableURLs(true)
 36		p.AllowURLSchemes("http", "https")
 37		p.AllowElements("a", "b", "i", "em", "strong")
 38		p.AllowAttrs("href").OnElements("a")
 39		p.RequireNoReferrerOnLinks(true)
 40		return p
 41	}
