 43	// SanitizeUsername removes any characters that are not lowercase letters or numbers
 44	func (s *Sanitizer) SanitizeUsername(username string) (string, error) {
 45		username = strings.TrimSpace(username)
 46	
 47		if !usernamePattern.MatchString(username) {
 48			return "", fmt.Errorf("username must only contain lowercase letters and numbers")
 49		}
 50	
 51		if utf8.RuneCountInString(username) < 3 || utf8.RuneCountInString(username) > 30 {
 52			return "", fmt.Errorf("username must be between 3 and 30 characters")
 53		}
 54	
 55		return username, nil
 56	}
 57	
 58	// SanitizeDisplayName removes HTML/script content but allows basic formatting
 59	func (s *Sanitizer) SanitizeDisplayName(displayName string) (string, error) {
 60		displayName = strings.TrimSpace(displayName)
 61	
 62		if len(displayName) == 0 {
 63			return "", fmt.Errorf("display name cannot be empty")
 64		}
 65		if len(displayName) > 50 {
 66			return "", fmt.Errorf("display name cannot exceed 50 characters")
 67		}
 68	
 69		if containsSuspiciousPatterns(displayName) {
 70			return "", fmt.Errorf("display name contains potentially dangerous content")
 71		}
 72	
 73		sanitized := strings.TrimSpace(s.strictPolicy.Sanitize(displayName))
 74		if sanitized == "" {
 75			return "", fmt.Errorf("display name cannot be empty")
 76		}
 77	
 78		return sanitized, nil
 79	}
 80	
 81	// SanitizeDescription removes dangerous HTML while allowing basic formatting
 82	func (s *Sanitizer) SanitizeDescription(description string) (string, error) {
 83		description = strings.TrimSpace(description)
 84	
 85		if len(description) > 2000 {
 86			return "", fmt.Errorf("description cannot exceed 2000 characters")
 87		}
 88	
 89		if containsSuspiciousPatterns(description) {
 90			return "", fmt.Errorf("description contains potentially dangerous content")
 91		}
 92	
 93		sanitized := strings.TrimSpace(s.basicPolicy.Sanitize(description))
 94	
 95		return sanitized, nil
 96	}
