 98	// SanitizeMarketTitle sanitizes market question titles
 99	func (s *Sanitizer) SanitizeMarketTitle(title string) (string, error) {
100		title = strings.TrimSpace(title)
101	
102		if len(title) == 0 {
103			return "", fmt.Errorf("market title cannot be empty")
104		}
105		if len(title) > 160 {
106			return "", fmt.Errorf("market title cannot exceed 160 characters")
107		}
108	
109		if containsSuspiciousPatterns(title) {
110			return "", fmt.Errorf("market title contains potentially dangerous content")
111		}
112	
113		sanitized := strings.TrimSpace(s.strictPolicy.Sanitize(title))
114		if sanitized == "" {
115			return "", fmt.Errorf("market title cannot be empty")
116		}
