121	// SanitizePersonalLink validates and sanitizes personal links
122	func (s *Sanitizer) SanitizePersonalLink(link string) (string, error) {
123		link = strings.TrimSpace(link)
124		if link == "" {
125			return "", nil
126		}
127	
128		if err := validatePersonalLinkLength(link); err != nil {
129			return "", err
130		}
131	
132		parsedURL, err := parseURLWithScheme(link)
133		if err != nil {
134			return "", err
135		}
136	
137		if err := validateAllowedScheme(parsedURL.Scheme); err != nil {
138			return "", err
139		}
140		if parsedURL.User != nil {
141			return "", fmt.Errorf("personal link cannot include credentials")
142		}
143		if parsedURL.Hostname() == "" {
144			return "", fmt.Errorf("personal link must include a valid host")
145		}
146	
147		if containsMaliciousDomain(parsedURL.Hostname()) {
148			return "", fmt.Errorf("potentially malicious domain detected")
149		}
150	
151		return parsedURL.String(), nil
152	}
153	
154	func validatePersonalLinkLength(link string) error {
155		if utf8.RuneCountInString(link) > 200 {
156			return fmt.Errorf("personal link cannot exceed 200 characters")
157		}
158		return nil
159	}
160	
161	func parseURLWithScheme(link string) (*url.URL, error) {
162		if strings.ContainsAny(link, " \t\r\n") {
163			return nil, fmt.Errorf("invalid URL format")
164		}
165	
166		parsedURL, err := url.Parse(link)
167		if err != nil {
168			return nil, fmt.Errorf("invalid URL format: %v", err)
169		}
170	
171		if parsedURL.Scheme != "" {
172			return parsedURL, nil
173		}
174	
175		withScheme := "https://" + link
176		parsedURL, err = url.Parse(withScheme)
177		if err != nil {
178			return nil, fmt.Errorf("invalid URL format after adding scheme: %v", err)
179		}
180		return parsedURL, nil
181	}
182	
183	func validateAllowedScheme(scheme string) error {
184		scheme = strings.ToLower(strings.TrimSpace(scheme))
185		if scheme != "http" && scheme != "https" {
186			return fmt.Errorf("only http and https URLs are allowed")
187		}
188		return nil
189	}
