192	func (s *Sanitizer) SanitizeEmoji(emoji string) (string, error) {
193		emoji = strings.TrimSpace(emoji)
194	
195		if !isValidEmoji(emoji) {
196			return "", fmt.Errorf("invalid emoji format")
197		}
198	
199		if utf8.RuneCountInString(emoji) > 20 {
200			return "", fmt.Errorf("emoji too long")
201		}
202	
203		return emoji, nil
204	}
