206	// SanitizePassword validates password strength
207	func (s *Sanitizer) SanitizePassword(password string) (string, error) {
208		password, err := s.CheckPasswordLength(password)
209		if err != nil {
210			return "", err
211		}
212	
213		password, err = s.CheckPasswordChars(password)
214		if err != nil {
215			return "", err
216		}
217	
218		return password, nil
219	}
220	
221	func (s *Sanitizer) CheckPasswordLength(password string) (string, error) {
222		const minLength = 8
223		const maxLength = 128
224	
225		length := utf8.RuneCountInString(password)
226		if length < minLength || length > maxLength {
227			return "", fmt.Errorf("password must be between %d and %d characters long", minLength, maxLength)
228		}
229	
230		return password, nil
231	}
232	
233	func (s *Sanitizer) CheckPasswordChars(password string) (string, error) {
234		for _, char := range password {
235			if unicode.IsSpace(char) || unicode.IsControl(char) {
236				return "", fmt.Errorf("password cannot contain whitespace or control characters")
237			}
238		}
239	
240		if !(hasUppercase(password) && hasLowercase(password) && hasDigit(password)) {
241			return "", fmt.Errorf("password must contain at least one uppercase letter, one lowercase letter, and one digit")
242		}
243	
244		return password, nil
245	}
