247	// containsSuspiciousPatterns checks for common XSS and injection patterns
248	func containsSuspiciousPatterns(input string) bool {
249		suspiciousPatterns := []string{
250			"javascript:",
251			"vbscript:",
252			"data:",
253			"<script",
254			"</script>",
255			"<iframe",
256			"<object",
257			"<embed",
258			"<link",
259			"<meta",
260			"<style",
261			"onload=",
262			"onerror=",
263			"onclick=",
264			"onmouseover=",
265			"onfocus=",
266			"onblur=",
267			"onchange=",
268			"onsubmit=",
269			"eval(",
270			"expression(",
271			"url(",
272			"@import",
273			"<!--",
274			"-->",
275		}
276	
277		inputLower := strings.ToLower(input)
278		for _, pattern := range suspiciousPatterns {
279			if strings.Contains(inputLower, pattern) {
280				return true
281			}
282		}
283	
284		return false
285	}
