287	// containsMaliciousDomain checks against known malicious domain patterns
288	func containsMaliciousDomain(domain string) bool {
289		domainLower := strings.ToLower(strings.TrimSpace(domain))
290		if domainLower == "" {
291			return true
292		}
293	
294		if ip := net.ParseIP(domainLower); ip != nil {
295			if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsUnspecified() {
296				return true
297			}
298			return false
299		}
300	
301		blockedDomains := []string{"bit.ly", "tinyurl.com", "t.co", "localhost"}
302		for _, blocked := range blockedDomains {
303			if domainLower == blocked || strings.HasSuffix(domainLower, "."+blocked) {
304				return true
305			}
306		}
307	
308		return false
309	}
