311	func isValidEmoji(emoji string) bool {
312		if emoji == "" {
313			return false
314		}
315	
316		hasUnicodeEmoji := false
317		hasASCIIEmoji := false
318		for _, r := range emoji {
319			switch {
320			case isEmojiRune(r):
321				hasUnicodeEmoji = true
322			case isASCIIEmojiRune(r):
323				hasASCIIEmoji = true
324			default:
325				return false
326			}
327		}
328		return hasUnicodeEmoji || hasASCIIEmoji
329	}
