 16	// DBConfig holds the normalized database configuration.
 17	type DBConfig struct {
 18		Host     string
 19		Port     string
 20		User     string
 21		Password string
 22		Name     string
 23		SSLMode  string
 24		TimeZone string
 25	}
 26	
 27	// DBFactory provides a hook to open a database using a given configuration.
 28	type DBFactory interface {
 29		Open(DBConfig) (*gorm.DB, error)
 30	}
 31	
 32	// PostgresFactory implements DBFactory using the postgres driver.
 33	type PostgresFactory struct {
 34		GormConfig *gorm.Config
 35	}
 36	
 37	// LoadDBConfigFromEnv normalizes env vars into a DBConfig.
 38	func LoadDBConfigFromEnv() (DBConfig, error) {
 39		cfg := DBConfig{
 40			Host:     firstNonEmpty(os.Getenv("DB_HOST"), os.Getenv("DBHOST")),
 41			User:     firstNonEmpty(os.Getenv("POSTGRES_USER"), os.Getenv("DB_USER")),
 42			Password: firstNonEmpty(os.Getenv("POSTGRES_PASSWORD"), os.Getenv("DB_PASS"), os.Getenv("DB_PASSWORD")),
 43			Name:     firstNonEmpty(os.Getenv("POSTGRES_DATABASE"), os.Getenv("POSTGRES_DB"), os.Getenv("DB_NAME")),
 44			Port:     firstNonEmpty(os.Getenv("POSTGRES_PORT"), os.Getenv("DB_PORT"), "5432"),
 45			SSLMode:  "disable",
 46			TimeZone: "UTC",
 47		}
 48	
 49		if cfg.Host == "" {
 50			return DBConfig{}, fmt.Errorf("missing DB host (DB_HOST or DBHOST)")
 51		}
 52		if cfg.User == "" {
 53			return DBConfig{}, fmt.Errorf("missing DB user (POSTGRES_USER or DB_USER)")
 54		}
 55		if cfg.Name == "" {
 56			return DBConfig{}, fmt.Errorf("missing DB name (POSTGRES_DATABASE/POSTGRES_DB/DB_NAME)")
 57		}
 58	
 59		return cfg, nil
 60	}
 61	
 62	// BuildPostgresDSN assembles the postgres DSN from config.
 63	func BuildPostgresDSN(cfg DBConfig) (string, error) {
 64		cfg.Host = strings.TrimSpace(cfg.Host)
 65		cfg.User = strings.TrimSpace(cfg.User)
 66		cfg.Name = strings.TrimSpace(cfg.Name)
 67		cfg.Port = strings.TrimSpace(cfg.Port)
 68		cfg.SSLMode = strings.TrimSpace(cfg.SSLMode)
 69		cfg.TimeZone = strings.TrimSpace(cfg.TimeZone)
 70	
 71		if cfg.Host == "" || cfg.User == "" || cfg.Name == "" {
 72			return "", fmt.Errorf("invalid DB config: host/user/name required")
 73		}
 74	
 75		port := cfg.Port
 76		if port == "" {
 77			port = "5432"
 78		}
 79	
 80		sslMode := cfg.SSLMode
 81		if sslMode == "" {
 82			sslMode = "disable"
 83		}
 84	
 85		timeZone := cfg.TimeZone
 86		if timeZone == "" {
 87			timeZone = "UTC"
 88		}
 89	
 90		dsn := fmt.Sprintf(
 91			"host=%s user=%s password=%s dbname=%s port=%s sslmode=%s TimeZone=%s",
 92			cfg.Host,
 93			cfg.User,
 94			cfg.Password,
 95			cfg.Name,
 96			port,
 97			sslMode,
 98			timeZone,
 99		)
100	
101		return dsn, nil
102	}
103	
104	// Open opens a postgres-backed gorm DB using the provided configuration.
105	func (f PostgresFactory) Open(cfg DBConfig) (*gorm.DB, error) {
106		dsn, err := BuildPostgresDSN(cfg)
107		if err != nil {
108			return nil, err
109		}
110	
111		gormCfg := f.GormConfig
112		if gormCfg == nil {
113			gormCfg = &gorm.Config{}
114		}
115	
116		return gorm.Open(postgres.Open(dsn), gormCfg)
117	}
118	
119	// InitDB initializes the global DB with the provided factory and config.
120	func InitDB(cfg DBConfig, factory DBFactory) (*gorm.DB, error) {
121		if factory == nil {
122			factory = PostgresFactory{}
123		}
124	
125		db, err := factory.Open(cfg)
126		if err != nil {
127			return nil, fmt.Errorf("open db: %w", err)
128		}
129		if db == nil {
130			return nil, fmt.Errorf("open db: factory returned nil db")
131		}
132	
133		dbMu.Lock()
134		DB = db
135		dbMu.Unlock()
136		return db, nil
137	}
138	
139	// GetDB returns the database connection.
140	func GetDB() *gorm.DB {
141		dbMu.RLock()
142		defer dbMu.RUnlock()
143		return DB
144	}
