 35		p.AllowStandardURLs()
 36		p.RequireParseableURLs(true)
 37		p.AllowURLSchemes("http", "https")
 38		p.AllowElements("a", "b", "i", "em", "strong")
 39		p.AllowAttrs("href").Matching(regexp.MustCompile(`^https?://`)).OnElements("a")
 40		p.RequireNoReferrerOnLinks(true)
 41		return p
