162	func parseURLWithScheme(link string) (*url.URL, error) {
163		if strings.ContainsAny(link, " \t\r\n") {
164			return nil, fmt.Errorf("invalid URL format")
165		}
166	
167		parsedURL, err := url.Parse(link)
168		if err != nil {
169			return nil, fmt.Errorf("invalid URL format: %v", err)
170		}
171	
172		if parsedURL.Scheme != "" {
173			if parsedURL.Host == "" {
174				return nil, fmt.Errorf("invalid URL format")
175			}
176			return parsedURL, nil
177		}
178	
179		withScheme := "https://" + link
180		parsedURL, err = url.Parse(withScheme)
181		if err != nil {
182			return nil, fmt.Errorf("invalid URL format after adding scheme: %v", err)
183		}
184		if parsedURL.Host == "" {
185			return nil, fmt.Errorf("invalid URL format")
186		}
187		return parsedURL, nil
188	}
