326	func isValidEmoji(emoji string) bool {
327		if emoji == "" {
328			return false
329		}
330	
331		hasUnicodeEmoji := false
332		hasASCIIEmoji := false
333		for _, r := range emoji {
334			switch {
335			case isEmojiRune(r):
336				hasUnicodeEmoji = true
337			case isASCIIEmojiRune(r):
338				hasASCIIEmoji = true
339				if hasUnicodeEmoji {
340					return false
341				}
342			default:
343				return false
344			}
345		}
346		return hasUnicodeEmoji || hasASCIIEmoji
347	}
348	
349	type runeRange struct {
350		start rune
351		end   rune
352	}
353	
354	var emojiRanges = []runeRange{
355		{start: 0x1F600, end: 0x1F64F}, // Emoticons
356		{start: 0x1F300, end: 0x1F5FF}, // Misc Symbols
357		{start: 0x1F680, end: 0x1F6FF}, // Transport
358		{start: 0x2600, end: 0x26FF},   // Misc symbols
359		{start: 0x2700, end: 0x27BF},   // Dingbats
360		{start: 0xFE00, end: 0xFE0F},   // Variation selectors
361		{start: 0x1F900, end: 0x1F9FF}, // Supplemental symbols
362		{start: 0x1F1E6, end: 0x1F1FF}, // Regional indicators
363	}
364	
365	func isEmojiRune(r rune) bool {
366		for _, emojiRange := range emojiRanges {
367			if r >= emojiRange.start && r <= emojiRange.end {
368				return true
369			}
370		}
371		return false
372	}
373	
374	func isASCIIEmojiRune(r rune) bool {
375		return strings.ContainsRune(":;=8xX()-[]{}\\/|^'\",.<>*oOPpD", r)
376	}
