 32	func LoginHandler(w http.ResponseWriter, r *http.Request) {
 33		if r.Method != http.MethodPost {
 34			http.Error(w, "Method is not supported.", http.StatusNotFound)
 35			return
 36		}
 37	
 38		securityService := security.NewSecurityService()
 39	
 40		req, err := decodeLoginRequest(r)
 41		if err != nil {
 42			http.Error(w, err.Error(), http.StatusBadRequest)
 43			return
 44		}
 45	
 46		req, err = validateAndSanitizeLogin(securityService, req)
 47		if err != nil {
 48			http.Error(w, err.Error(), http.StatusBadRequest)
 49			return
 50		}
 51	
 52		db := util.GetDB()
 53		if db == nil {
 54			http.Error(w, "Error accessing database", http.StatusInternalServerError)
 55			return
 56		}
 57	
 58		user, loginErr := authenticateUser(db, req)
 59		if loginErr != nil {
 60			http.Error(w, loginErr.message, loginErr.statusCode)
 61			return
 62		}
 63	
 64		jwtKey := getJWTKey()
 65		if len(jwtKey) == 0 {
 66			http.Error(w, "Error creating token", http.StatusInternalServerError)
 67			return
 68		}
 69	
 70		tokenString, err := generateJWT(user.Username, jwtKey)
 71		if err != nil {
 72			http.Error(w, "Error creating token", http.StatusInternalServerError)
 73			return
 74		}
 75	
 76		writeLoginResponse(w, user, tokenString)
 77	}
