 79	type loginRequest struct {
 80		Username string `json:"username" validate:"required,min=3,max=30,username"`
 81		Password string `json:"password" validate:"required,min=1"`
 82	}
 83	
 84	func decodeLoginRequest(r *http.Request) (loginRequest, error) {
 85		var req loginRequest
 86		decoder := json.NewDecoder(io.LimitReader(r.Body, 1<<20))
 87		decoder.DisallowUnknownFields()
 88		if err := decoder.Decode(&req); err != nil {
 89			return loginRequest{}, fmt.Errorf("error reading request body")
 90		}
 91		if err := decoder.Decode(&struct{}{}); err != io.EOF {
 92			return loginRequest{}, fmt.Errorf("error reading request body")
 93		}
 94		return req, nil
 95	}
