 97	func validateAndSanitizeLogin(securityService *security.SecurityService, req loginRequest) (loginRequest, error) {
 98		sanitizedUsername, err := securityService.Sanitizer.SanitizeUsername(req.Username)
 99		if err != nil {
100			return req, fmt.Errorf("invalid input")
101		}
102		req.Username = sanitizedUsername
103	
104		if err := securityService.Validator.ValidateStruct(req); err != nil {
105			return req, fmt.Errorf("invalid input")
106		}
107	
108		return req, nil
109	}
