116	func authenticateUser(db *gorm.DB, req loginRequest) (models.User, *loginError) {
117		if db == nil {
118			return models.User{}, &loginError{message: "Error accessing database", statusCode: http.StatusInternalServerError}
119		}
120	
121		user, err := findUserByUsername(db, req.Username)
122		if err != nil {
123			if errors.Is(err, gorm.ErrRecordNotFound) {
124				return models.User{}, &loginError{message: "Invalid Credentials", statusCode: http.StatusUnauthorized}
125			}
126			return models.User{}, &loginError{message: "Error accessing database", statusCode: http.StatusInternalServerError}
127		}
128	
129		if !user.CheckPasswordHash(req.Password) {
130			return models.User{}, &loginError{message: "Invalid Credentials", statusCode: http.StatusUnauthorized}
131		}
132	
133		return user, nil
134	}
