136	func findUserByUsername(db *gorm.DB, username string) (models.User, error) {
137		if db == nil {
138			return models.User{}, fmt.Errorf("database connection is not initialized")
139		}
140	
141		var user models.User
142		result := db.Where("username = ?", username).First(&user)
143		return user, result.Error
144	}
