146	func generateJWT(username string, jwtKey []byte) (string, error) {
147		if len(jwtKey) == 0 {
148			return "", fmt.Errorf("missing JWT signing key")
149		}
150	
151		claims := &UserClaims{
152			Username: username,
153			StandardClaims: jwt.StandardClaims{
154				ExpiresAt: time.Now().UTC().Add(24 * time.Hour).Unix(),
155			},
156		}
157	
158		token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
159		return token.SignedString(jwtKey)
160	}
